```java
import java.util.PriorityQueue;

public class Solution {
    public static long solve(long m, long n, long[][] waitCost) {
        long[][][] dist = new long[(int)m][(int)n][2];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                dist[i][j][0] = Long.MAX_VALUE;
                dist[i][j][1] = Long.MAX_VALUE;
            }
        }
        dist[0][0][1] = 1;
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{1, 0, 0, 1});
        int[][] directions = {{0, 1}, {1, 0}};
        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long current_cost = current[0];
            int i = current[1];
            int j = current[2];
            int parity = current[3];
            if (i == (int)m - 1 && j == (int)n - 1) {
                return current_cost;
            }
            if (current_cost > dist[i][j][parity]) {
                continue;
            }
            if (parity == 1) {
                for (int[] dir : directions) {
                    int ni = i + dir[0];
                    int nj = j + dir[1];
                    if (ni < (int)m && nj < (int)n) {
                        long new_cost = current_cost + (ni + 1) * (nj + 1);
                        if (new_cost < dist[ni][nj][0]) {
                            dist[ni][nj][0] = new_cost;
                            pq.offer(new long[]{new_cost, ni, nj, 0});
                        }
                    }
                }
            } else {
                long new_cost = current_cost + waitCost[i][j];
                if (new_cost < dist[i][j][1]) {
                    dist[i][j][1] = new_cost;
                    pq.offer(new long[]{new_cost, i, j, 1});
                }
            }
        }
        return -1;
    }
}
