import java.util.PriorityQueue;

public class Solution {
    public static long solve(long m, long n, long[][] waitCost) {
        int rows = (int) m;
        int cols = (int) n;
        long[][][] dist = new long[rows][cols][2];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                dist[i][j][0] = Long.MAX_VALUE;
                dist[i][j][1] = Long.MAX_VALUE;
            }
        }
        dist[0][0][1] = 1;
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{1, 0, 0, 1});
        int[][] directions = {{0, 1}, {1, 0}};

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long currentCost = current[0];
            int i = current[1];
            int j = current[2];
            int parity = current[3];

            if (i == rows - 1 && j == cols - 1) {
                return currentCost;
            }

            if (currentCost > dist[i][j][parity]) {
                continue;
            }

            if (parity == 1) {
                for (int[] dir : directions) {
                    int ni = i + dir[0];
                    int nj = j + dir[1];
                    if (ni < rows && nj < cols) {
                        long newCost = currentCost + (ni + 1) * (nj + 1);
                        if (newCost < dist[ni][nj][0]) {
                            dist[ni][nj][0] = newCost;
                            pq.offer(new long[]{newCost, ni, nj, 0});
                        }
                    }
                }
            } else {
                long newCost = currentCost + waitCost[i][j];
                if (newCost < dist[i][j][1]) {
                    dist[i][j][1] = newCost;
                    pq.offer(new long[]{newCost, i, j, 1});
                }
            }
        }
        return -1;
    }
}
